using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Visão Nocturna (P8 — Coruja H2, hasVision / PrimaryAbility.NightVision).
///
/// Toggle (sem cooldown/duração): ao premir o botão de habilidade, activa;
/// ao premir de novo, desactiva. Enquanto ACTIVA, revela periodicamente todos
/// os <see cref="NightVisionRevealable"/> dentro de 'form.nightVisionRadius'
/// (fade in + colisão "transparente para o player" — ver NightVisionRevealable),
/// e esconde de novo (fade out + colisão normal) os que saírem do raio. Ao
/// desactivar, esconde todos os que ainda estavam revelados.
/// </summary>
public class NightVisionAbility : MonoBehaviour, IFormAbility, IAbility, IActiveAbility
{
    [Tooltip("Repete a verificação do raio a cada X segundos (revela novos / esconde os que saíram).")]
    public float refreshInterval = 0.2f;

    [SerializeField] private Collider2D playerCollider;

    private bool enabledForForm;
    private bool isActive;
    private float refreshTimer;
    private float radius;

    private readonly HashSet<NightVisionRevealable> revealed = new HashSet<NightVisionRevealable>();
    private static readonly Collider2D[] OverlapBuffer = new Collider2D[32];

    /// <summary>true enquanto a visão nocturna está activa (toggle).</summary>
    public bool IsActive => isActive;

    private void Awake()
    {
        if (playerCollider == null) playerCollider = GetComponent<Collider2D>();
    }

    public void ConfigureFromForm(AnimalFormData form)
    {
        enabledForForm = form != null && form.hasVision;
        radius = form != null ? form.nightVisionRadius : 0f;

        if (!enabledForForm) Deactivate();
    }

    /// <summary>Chamado pelo AbilityRouter (OnAbilityPressed) quando a forma tem PrimaryAbility.NightVision.</summary>
    public void Toggle()
    {
        if (!enabledForForm) return;

        if (isActive) Deactivate();
        else Activate();
    }

    private void Activate()
    {
        if (isActive) return;

        isActive = true;
        refreshTimer = 0f; // força verificação já no próximo Update
    }

    private void Deactivate()
    {
        if (!isActive) return;

        isActive = false;

        foreach (var r in revealed)
        {
            if (r != null) r.SetRevealed(false, playerCollider);
        }
        revealed.Clear();
    }

    private void Update()
    {
        if (!isActive) return;

        refreshTimer -= Time.deltaTime;
        if (refreshTimer > 0f) return;
        refreshTimer = refreshInterval;

        RefreshRevealed();
    }

    private void RefreshRevealed()
    {
        int count = Physics2D.OverlapCircleNonAlloc(transform.position, radius, OverlapBuffer);

        // Marca quais continuam dentro do raio (revela novos).
        HashSet<NightVisionRevealable> stillInRange = null;

        for (int i = 0; i < count; i++)
        {
            var hit = OverlapBuffer[i];
            if (hit == null) continue;

            var r = hit.GetComponent<NightVisionRevealable>();
            if (r == null) continue;

            if (stillInRange == null) stillInRange = new HashSet<NightVisionRevealable>();
            stillInRange.Add(r);

            if (!revealed.Contains(r))
            {
                r.SetRevealed(true, playerCollider);
                revealed.Add(r);
            }
        }

        // Esconde os que saíram do raio.
        if (revealed.Count > 0)
        {
            revealed.RemoveWhere(r =>
            {
                if (r == null) return true;

                bool stillIn = stillInRange != null && stillInRange.Contains(r);
                if (!stillIn)
                {
                    r.SetRevealed(false, playerCollider);
                    return true;
                }
                return false;
            });
        }
    }

    private void OnDisable() => Deactivate();

    private void OnDrawGizmosSelected()
    {
        Gizmos.color = new Color(0.4f, 0.7f, 1f, 0.35f);
        Gizmos.DrawWireSphere(transform.position, radius);
    }

    // ---- IAbility / IActiveAbility (Tarefa #34 — HUD) ----
    // Toggle sem cooldown: Activate alterna (Toggle); Cancel desactiva
    // imediatamente (transformar, morrer, etc.). IsActive já existe como
    // propriedade pública (implementa IAbility.IsActive implicitamente).
    void IAbility.Activate() => Toggle();
    void IAbility.Release() { }
    public void Cancel(AbilityCancelReason reason) => Deactivate();
    public float CooldownRemaining => 0f;
    public float CooldownDuration => 0f;
    public bool CanActivate => enabledForForm;

    /// <summary>AnimalsDebugPanel — sem cooldown próprio (no-op).</summary>
    public void ResetCooldown() { }
}
